#include<bits/stdc++.h>
using namespace std;
int n,m,a[100005],l,r,mid,ans;
bool f(int x){
    int p=0,ans=0;
    for(int i=1;i<=n;++i){
        if(p+a[i]<=x)p+=a[i];
        else p=a[i],++ans;
        if(ans>=m)return true;
    }
    return false;
}
int main(void){
    cin>>n>>m;
    for(int i=1;i<=n;++i)cin>>a[i],l=max(l,a[i]),r+=a[i];
    while(l<=r){
        mid=(l+r)/2;
        if(f(mid))l=mid+1;
        else r=mid-1;
    }
    cout<<l;
    return false;
}
